+	sample := []byte(`{
+		"version": "1.0.0",
+		"commit": "abc123",
+		"build_date": "2025-01-01",
+		"built_by": "test",
+		"go_version": "go1.25",
+		"os": "linux",
+		"arch": "amd64"
+	}`)
+
+	b.ResetTimer()
+	for i := 0; i < b.N; i++ {
+		var obj map[string]any
+		_ = json.Unmarshal(sample, &obj)
+	}
+}

